   516→
   517→        let mut coefficients = Vec::new();
   518→        let mut residuals = Vec::new();
   519→        let mut fitted_values = Vec::new();
   520→
   521→        for result in reader.records() {
   522→            let record = result?;
   523→            let metric = &record[0];
   524→            let value_str = &record[1];
   525→            // Note: record[2] contains the index, but we don't need it
   526→
   527→            // Skip NA values from R
   528→            if value_str == "NA" {
   529→                continue;
   530→            }
   531→
   532→            let value: f64 = value_str.parse()?;
   533→
   534→            match metric {
   535→                "coefficients" => coefficients.push(value),
   536→                "residuals" => residuals.push(value),
   537→                "fitted_values" => fitted_values.push(value),
   538→                _ => {} // ignore other metrics for now
   539→            }
   540→        }
   541→
   542→        Ok(RResults {
   543→            coefficients,
