use ndarray::{Array1, Array2};
use rand::prelude::*;
use rand::rngs::StdRng;
use rand::SeedableRng;
use rand_distr::StandardNormal;
use stats_models::{Lm, Fit};

fn main() {
    println!("R vs stats-rs Linear Model Comparison");
    println!("=====================================");

    // Generate random data (using seed for reproducibility)
    let n_obs = 100;
    let mut rng = StdRng::seed_from_u64(42);

    // Generate X matrix with intercept column
    let mut x_data = Vec::with_capacity(n_obs * 2);
    let mut x_values = Vec::with_capacity(n_obs);

    for _ in 0..n_obs {
        let x = rng.sample::<f64, _>(StandardNormal);
        x_data.push(1.0); // intercept
        x_data.push(x);   // predictor
        x_values.push(x);
    }

    // Generate y = 2.5 + 1.8*x + noise
    let mut y_data = Vec::with_capacity(n_obs);
    for &x in &x_values {
        let noise = rng.sample::<f64, _>(StandardNormal) * 0.5;
        let y = 2.5 + 1.8 * x + noise;
        y_data.push(y);
    }

    // Create ndarray views
    let x_array = Array2::from_shape_vec((n_obs, 2), x_data.clone()).unwrap();
    let y_array = Array1::from(y_data.clone());

    // Fit stats-rs model
    let rust_fit = Lm::fit_ndarray(x_array.view(), y_array.view()).unwrap();

    // Display results
    println!("Data Summary:");
    println!("  Observations: {}", n_obs);
    println!("  True intercept: 2.5");
    println!("  True slope: 1.8");
    println!("  Error std dev: 0.5");
    println!();

    println!("stats-rs Results:");
    println!("  Intercept: {:.6}", rust_fit.coefficients()[0]);
    println!("  Slope: {:.6}", rust_fit.coefficients()[1]);
    println!("  R-squared: {:.6}", rust_fit.summary().r_squared);
    println!("  Residual SE: {:.6}", rust_fit.summary().residual_std_error);
    println!("  F-statistic: {:.6}", rust_fit.summary().f_statistic);
    println!();

    // Generate R script for comparison
    let r_script = format!(r#"
# R Comparison Script
# Generated data (same as Rust)
set.seed(42)
n_obs <- {}
x <- rnorm(n_obs)
y <- 2.5 + 1.8 * x + rnorm(n_obs, 0, 0.5)

# Fit linear model
r_fit <- lm(y ~ x)
summary_r <- summary(r_fit)

# Display results
cat("R Results:\n")
cat("  Intercept:", coef(r_fit)[1], "\n")
cat("  Slope:", coef(r_fit)[2], "\n")
cat("  R-squared:", summary_r$r.squared, "\n")
cat("  Residual SE:", summary_r$sigma, "\n")
cat("  F-statistic:", summary_r$fstatistic[1], "\n")
cat("\n")

# Print detailed comparison
cat("Detailed Comparison:\n")
cat("                     R         stats-rs    Difference\n")
cat("Intercept:      ", sprintf("%9.6f", coef(r_fit)[1]), "  {:.6}  ", 
    sprintf("%9.6f", coef(r_fit)[1] - {:.6}), "\n")
cat("Slope:          ", sprintf("%9.6f", coef(r_fit)[2]), "  {:.6}  ", 
    sprintf("%9.6f", coef(r_fit)[2] - {:.6}), "\n")
cat("R-squared:      ", sprintf("%9.6f", summary_r$r.squared), "  {:.6}  ", 
    sprintf("%9.6f", summary_r$r.squared - {:.6}), "\n")
cat("Residual SE:    ", sprintf("%9.6f", summary_r$sigma), "  {:.6}  ", 
    sprintf("%9.6f", summary_r$sigma - {:.6}), "\n")
cat("F-statistic:    ", sprintf("%9.6f", summary_r$fstatistic[1]), "  {:.6}  ", 
    sprintf("%9.6f", summary_r$fstatistic[1] - {:.6}), "\n")
"#, 
        n_obs,
        rust_fit.coefficients()[0],
        rust_fit.coefficients()[1],
        rust_fit.summary().r_squared,
        rust_fit.summary().residual_std_error,
        rust_fit.summary().f_statistic,
        rust_fit.coefficients()[0], rust_fit.coefficients()[1],
        rust_fit.summary().r_squared, rust_fit.summary().residual_std_error,
        rust_fit.summary().f_statistic
    );

    // Write R script to file
    std::fs::write("r_comparison.R", r_script).expect("Failed to write R script");

    println!("R comparison script written to 'r_comparison.R'");
    println!("Run: Rscript r_comparison.R");
    println!();

    // Display expected differences
    println!("Expected Results:");
    println!("  Both models should show nearly identical results");
    println!("  Differences should be < 1e-10 (numerical precision)");
    println!("  This demonstrates stats-rs achieves R-level accuracy");
}

