// Debug script to understand rank-deficient matrix handling
use faer::{prelude::*, Mat};

fn main() {
    // Create the same rank-deficient matrix as in the failing test
    // Design matrix: [1, x1, x2] where x2 = 0.5 * x1
    let n_obs = 8;
    let x1_values: Vec<f64> = (1..=n_obs).map(|i| i as f64).collect();
    let x2_values: Vec<f64> = (1..=n_obs).map(|i| (i as f64) * 0.5).collect();

    let mut x_data = Vec::with_capacity(n_obs * 3);
    for i in 0..n_obs {
        x_data.push(1.0); // intercept
        x_data.push(x1_values[i]); // x1
        x_data.push(x2_values[i]); // x2 = 0.5 * x1 (causing multicollinearity)
    }

    // Create response with same formula as test
    let y_values: Vec<f64> = x1_values
        .iter()
        .zip(x2_values.iter())
        .map(|(&x1, &x2)| 2.0 + 1.5 * x1 + 0.8 * x2 + 0.1 * x1 * x2.sin())
        .collect();

    // Create faer matrices
    let x_mat = Mat::from_fn(n_obs, 3, |i, j| x_data[i * 3 + j]);
    let y_mat = Mat::from_fn(n_obs, 1, |i, _| y_values[i]);

    println!("Design matrix X:");
    println!("{}", x_mat);

    println!("\nResponse vector y:");
    println!("{}", y_mat);

    // Check condition number
    let svd = x_mat.svd();
    let singular_values = svd.S();
    println!("\nSingular values:");
    for i in 0..singular_values.nrows() {
        println!("  σ{}: {}", i + 1, singular_values[i]);
    }

    let condition_number = singular_values[0] / singular_values[singular_values.nrows() - 1];
    println!("Condition number: {}", condition_number);

    // QR decomposition
    let qr = x_mat.col_piv_qr();
    let r_matrix = qr.R();
    let perm = qr.col_permutation();

    println!("\nQR decomposition:");
    println!("R matrix:");
    println!("{}", r_matrix);

    println!("\nColumn permutation:");
    for i in 0..perm.len() {
        println!("  perm[{}] = {}", i, perm.indices()[i]);
    }

    // Check rank detection
    let tolerance = 1e-12;
    let mut rank = 0;
    for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
        let diag_val = r_matrix[(i, i)].abs();
        println!("R[{}, {}] = {}", i, i, diag_val);
        if diag_val > tolerance {
            rank += 1;
        }
    }
    println!("Detected rank: {}", rank);

    // Try solving
    let coefficients_mat = qr.solve_lstsq(&y_mat);
    println!("\nCoefficients from solve_lstsq:");
    for i in 0..coefficients_mat.nrows() {
        println!("  β{}: {}", i, coefficients_mat[(i, 0)]);
    }

    // Calculate fitted values
    let fitted_mat = &x_mat * &coefficients_mat;
    println!("\nFitted values:");
    for i in 0..fitted_mat.nrows() {
        println!("  ŷ{}: {}", i, fitted_mat[(i, 0)]);
    }
}

//! Core optimization algorithms for statistical MLE
//!
//! This crate provides generic optimization algorithms tailored for statistical
//! model fitting, including IRLS, L-BFGS-B, and coordinate descent solvers.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use faer::{prelude::*, Mat};
use ndarray::{Array1, Array2, ArrayView1, ArrayView2};

/// Optimization errors
#[derive(thiserror::Error, Debug)]
pub enum OptimError {
    /// Convergence failure
    #[error("Failed to converge after {0} iterations")]
    Convergence(usize),
    /// Numerical issue
    #[error("Numerical error: {0}")]
    Numerical(String),
}

/// Optimization result
#[derive(Debug)]
pub struct OptimResult {
    /// Final parameter estimates
    pub params: Array1<f64>,
    /// Number of iterations
    pub iterations: usize,
    /// Converged successfully
    pub converged: bool,
    /// Final deviance
    pub deviance: f64,
    /// Final working weights
    pub weights: Array1<f64>,
    /// Final linear predictor values
    pub linear_predictor: Array1<f64>,
}

/// IRLS working data for one iteration
#[derive(Debug)]
pub struct IrlsWorkingData {
    /// Linear predictor η = X * β
    pub eta: Array1<f64>,
    /// Mean μ = g⁻¹(η)
    pub mu: Array1<f64>,
    /// Working weights w = (g'(μ))² / V(μ)
    pub weights: Array1<f64>,
    /// Working response z = η + (y - μ) * g'(μ)
    pub working_response: Array1<f64>,
    /// Current deviance
    pub deviance: f64,
}

/// Configuration for IRLS algorithm
#[derive(Debug)]
pub struct IrlsConfig {
    /// Maximum iterations
    pub max_iter: usize,
    /// Convergence tolerance for deviance
    pub tolerance: f64,
    /// Minimum weight to prevent numerical issues
    pub min_weight: f64,
    /// Use acceleration methods (Anderson acceleration, SQUAREM)
    pub use_acceleration: bool,
    /// Step size damping factor for problematic cases
    pub step_damping: f64,
    /// Enable adaptive step sizing
    pub adaptive_step: bool,
}

/// Bundle of GLM family functions for IRLS
pub struct GlmFunctions<LF, ILF, MEF, VF, DR> {
    /// Link function g(μ)
    pub link_fn: LF,
    /// Inverse link function g⁻¹(η)
    pub inverse_link_fn: ILF,
    /// Derivative dμ/dη
    pub mu_eta_fn: MEF,
    /// Variance function V(μ)
    pub variance_fn: VF,
    /// Deviance residual function
    pub dev_resid_fn: DR,
}

/// Configuration for coordinate descent solver
#[derive(Debug, Clone)]
pub struct CoordinateDescentConfig {
    /// Maximum iterations
    pub max_iter: usize,
    /// Convergence tolerance for coefficients
    pub tolerance: f64,
    /// L1 regularization parameter (lambda)
    pub lambda: f64,
    /// Elastic net mixing parameter (alpha): 1.0 = Lasso, 0.0 = Ridge
    pub alpha: f64,
    /// Whether to standardize features
    pub standardize: bool,
}

