   213→impl Lm {
   214→    /// Fit a linear model using ndarray views (recommended modern API)
   215→    ///
   216→    /// This implementation uses faer's column-pivoted QR decomposition to handle
   217→    /// rank-deficient design matrices robustly, as is common in statistical modeling.
   218→    ///
   219→    /// # Arguments
   220→    /// * `x` - Design matrix as ndarray view (n_observations × n_predictors)
   221→    /// * `y` - Response vector as ndarray view (n_observations)
   222→    ///
   223→    /// # Example
   224→    /// ```
   225→    /// use ndarray::Array2;
   226→    /// use stats_models::Lm;
   227→    ///
   228→    /// // Create design matrix with intercept
   229→    /// let x = Array2::from_shape_vec((3, 2), vec![1.0, 1.0, 1.0, 2.0, 1.0, 3.0]).unwrap();
   230→    /// let y = vec![3.0, 5.0, 7.0];
   231→    ///
   232→    /// let fit = Lm::fit_ndarray(x.view(), ndarray::Array1::from(y).view()).unwrap();
   233→    /// ```
   234→    pub fn fit_ndarray(x: ArrayView2<f64>, y: ArrayView1<f64>) -> Result<LmFit, ModelError> {
   235→        let (n_rows, n_cols) = x.dim();
   236→
   237→        if y.len() != n_rows {
   238→            return Err(ModelError::InvalidModel(
   239→                "Response vector length doesn't match number of observations".to_string(),
   240→            ));
   241→        }
   242→
   243→        // Convert to faer matrices
   244→        let x_mat = Mat::from_fn(n_rows, n_cols, |i, j| x[[i, j]]);
   245→        let y_mat = Mat::from_fn(n_rows, 1, |i, _| y[i]);
   246→
   247→        Self::fit_internal(x_mat, y_mat, n_rows, n_cols)
   248→    }
   249→
   250→    /// Fit a linear model using raw slices (legacy API for backward compatibility)
   251→    ///
   252→    /// This implementation uses faer's column-pivoted QR decomposition to handle
   253→    /// rank-deficient design matrices robustly, as is common in statistical modeling.
   254→    ///
   255→    /// **Note**: Consider using `fit_ndarray` for better type safety and ergonomics.
   256→    pub fn fit(
   257→        x_data: &[f64],
   258→        y_data: &[f64],
   259→        n_rows: usize,
   260→        n_cols: usize,
   261→    ) -> Result<LmFit, ModelError> {
   262→        if x_data.len() != n_rows * n_cols {
   263→            return Err(ModelError::InvalidModel(
   264→                "Design matrix dimensions don't match data".to_string(),
   265→            ));
   266→        }
   267→
   268→        if y_data.len() != n_rows {
   269→            return Err(ModelError::InvalidModel(
   270→                "Response vector length doesn't match number of observations".to_string(),
   271→            ));
   272→        }
   273→
   274→        // Create faer matrices from input data
   275→        let x_mat = Mat::from_fn(n_rows, n_cols, |i, j| x_data[i * n_cols + j]);
   276→        let y_mat = Mat::from_fn(n_rows, 1, |i, _| y_data[i]);
   277→
   278→        Self::fit_internal(x_mat, y_mat, n_rows, n_cols)
   279→    }
   280→
   281→    /// Internal fitting logic shared by both APIs
   282→    fn fit_internal(
   283→        x_mat: Mat<f64>,
   284→        y_mat: Mat<f64>,
   285→        n_rows: usize,
   286→        n_cols: usize,
   287→    ) -> Result<LmFit, ModelError> {
   288→        // Use column-pivoted QR for numerical stability with rank-deficient matrices
   289→        let qr = x_mat.col_piv_qr();
   290→
   291→        // Calculate rank from R matrix diagonal elements
   292→        let r_matrix = qr.R();
   293→        let tolerance = 1e-12;
   294→        let mut rank = 0;
   295→        for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
   296→            if r_matrix[(i, i)].abs() > tolerance {
   297→                rank += 1;
   298→            }
   299→        }
   300→
   301→        // Handle rank-deficient matrices by checking for numerical instability
   302→        let coefficients_mat = qr.solve_lstsq(&y_mat);
   303→
   304→        // Check for numerical instability and apply correction if needed
   305→        let has_instability =
   306→            (0..coefficients_mat.nrows()).any(|i| coefficients_mat[(i, 0)].abs() > 1e10);
   307→
   308→        let final_coefficients_mat = if has_instability {
   309→            // For rank-deficient case, set coefficients for columns beyond rank to zero
   310→            let mut corrected_coefs = Vec::new();
   311→            for i in 0..coefficients_mat.nrows() {
   312→                let coef = coefficients_mat[(i, 0)];
   313→                if coef.abs() > 1e10 {
   314→                    corrected_coefs.push(0.0);
   315→                } else {
   316→                    corrected_coefs.push(coef);
   317→                }
   318→            }
   319→            Mat::from_fn(n_cols, 1, |i, _| corrected_coefs[i])
   320→        } else {
   321→            coefficients_mat
   322→        };
   323→
   324→        // Calculate fitted values: ŷ = X * β (using corrected coefficients)
   325→        let fitted_mat = &x_mat * &final_coefficients_mat;
   326→
   327→        // Calculate residuals: e = y - ŷ
   328→        let residuals_mat = &y_mat - &fitted_mat;
   329→
   330→        // Extract results to plain Vec<f64> for API
   331→        let coefficients: Vec<f64> = (0..final_coefficients_mat.nrows())
   332→            .map(|i| final_coefficients_mat[(i, 0)])
   333→            .collect();
   334→
   335→        let fitted_values: Vec<f64> = (0..fitted_mat.nrows())
   336→            .map(|i| fitted_mat[(i, 0)])
   337→            .collect();
   338→
   339→        let residuals: Vec<f64> = (0..residuals_mat.nrows())
   340→            .map(|i| residuals_mat[(i, 0)])
   341→            .collect();
   342→
   343→        // rank is already computed above using qr.rank()
   344→
   345→        Ok(LmFit {
   346→            coefficients,
   347→            fitted_values,
   348→            residuals,
   349→            n_obs: n_rows,
   350→            rank,
   351→            x_matrix: x_mat,
   352→        })
   353→    }
   354→}
