   356→impl LmFit {
   357→    /// Get the number of observations used in the model
   358→    pub fn n_obs(&self) -> usize {
   359→        self.n_obs
   360→    }
   361→
   362→    /// Get the rank of the design matrix (number of linearly independent columns)
   363→    pub fn rank(&self) -> usize {
   364→        self.rank
   365→    }
   366→
   367→    /// Get degrees of freedom for error (n_obs - rank)
   368→    pub fn df_resid(&self) -> usize {
   369→        self.n_obs.saturating_sub(self.rank)
   370→    }
   371→    
   372→    /// Compute model diagnostics
   373→    pub fn diagnostics(&self) -> diagnostics::ModelDiagnostics {
   374→        let sigma = self.sigma();
   375→        diagnostics::compute_diagnostics(&self.x_matrix, &self.residuals, sigma)
   376→    }
   377→    
   378→    /// Compute residual standard error
   379→    pub fn sigma(&self) -> f64 {
   380→        let rss: f64 = self.residuals.iter().map(|r| r * r).sum();
   381→        let df_resid = self.df_resid() as f64;
   382→        if df_resid > 0.0 {
   383→            (rss / df_resid).sqrt()
   384→        } else {
   385→            0.0
   386→        }
   387→    }
   388→    
   389→    /// Get variance-covariance matrix of parameters
   390→    pub fn vcov(&self) -> Mat<f64> {
   391→        let sigma_sq = self.sigma().powi(2);
   392→        
   393→        // Compute (X'X)^(-1)
   394→        let xtx = self.x_matrix.transpose() * &self.x_matrix;
   395→        let qr = xtx.col_piv_qr();
   396→        let identity = Mat::identity(xtx.nrows(), xtx.ncols());
   397→        let xtx_inv = qr.solve(&identity);
   398→        
   399→        // Multiply by sigma^2
   400→        Mat::from_fn(xtx_inv.nrows(), xtx_inv.ncols(), |i, j| {
   401→            sigma_sq * xtx_inv[(i, j)]
   402→        })
   403→    }
   404→    
   405→    /// Compute confidence intervals for parameters
   406→    pub fn confint(&self, level: f64) -> Result<Vec<intervals::ConfidenceInterval>, ModelError> {
   407→        let vcov = self.vcov();
   408→        let std_errors: Vec<f64> = (0..self.coefficients.len())
   409→            .map(|i| vcov[(i, i)].sqrt())
   410→            .collect();
   411→        
   412→        intervals::parameter_confidence_intervals(
   413→            &self.coefficients,
   414→            &std_errors,
   415→            Some(self.df_resid()),
   416→            level
   417→        ).map_err(|e| ModelError::InvalidModel(e))
   418→    }
   419→    
   420→    /// Compute prediction intervals for new observations
   421→    pub fn predict_interval(
   422→        &self,
   423→        x_new: &Mat<f64>,
   424→        level: f64
   425→    ) -> Result<Vec<intervals::PredictionInterval>, ModelError> {
   426→        let vcov = self.vcov();
   427→        let sigma = self.sigma();
   428→        
   429→        intervals::prediction_intervals(
   430→            x_new,
   431→            &self.coefficients,
   432→            &vcov,
   433→            sigma,
   434→            self.df_resid(),
   435→            level
   436→        ).map_err(|e| ModelError::InvalidModel(e))
   437→    }
   438→    
   439→    /// Perform Wald test
   440→    pub fn wald_test(
   441→        &self,
   442→        r_matrix: &Mat<f64>,
   443→        r_values: Option<&[f64]>
   444→    ) -> Result<hypothesis_tests::TestResult, ModelError> {
   445→        let vcov = self.vcov();
   446→        hypothesis_tests::wald_test(&self.coefficients, &vcov, r_matrix, r_values)
   447→            .map_err(|e| ModelError::InvalidModel(e))
   448→    }
   449→}
