   829→impl Fit for GlmFit {
   830→    fn coefficients(&self) -> &[f64] {
   831→        &self.coefficients
   832→    }
   833→
   834→    fn fitted(&self) -> &[f64] {
   835→        &self.fitted_values
   836→    }
   837→
   838→    fn residuals(&self) -> &[f64] {
   839→        &self.residuals
   840→    }
   841→
   842→    fn summary(&self) -> ModelSummary {
   843→        use inference::{f_test_p_value, model_f_statistic, t_statistics, t_test_p_values};
   844→
   845→        // For GLM, use deviance-based statistics
   846→        let rss: f64 = self.residuals.iter().map(|r| r * r).sum();
   847→        let n = self.n_obs as f64;
   848→        let p = self.coefficients.len() as f64;
   849→        let df_resid = (n - p).max(0.0);
   850→
   851→        // Use deviance for dispersion estimation in GLM
   852→        let dispersion = if df_resid > 0.0 {
   853→            self.deviance / df_resid
   854→        } else {
   855→            1.0
   856→        };
   857→        let residual_std_error = dispersion.sqrt();
   858→
   859→        // For GLM, R² is calculated differently (based on deviance)
   860→        // Null deviance would be calculated with intercept-only model
   861→        // For now, use a simplified version
   862→        let y_mean: f64 = self
   863→            .fitted_values
   864→            .iter()
   865→            .zip(self.residuals.iter())
   866→            .map(|(fitted, resid)| fitted + resid)
   867→            .sum::<f64>()
   868→            / n;
   869→
   870→        let tss: f64 = self
   871→            .fitted_values
   872→            .iter()
   873→            .zip(self.residuals.iter())
   874→            .map(|(fitted, resid)| {
   875→                let y = fitted + resid;
   876→                (y - y_mean).powi(2)
   877→            })
   878→            .sum();
   879→
   880→        let r_squared = if tss > 0.0 { 1.0 - rss / tss } else { 0.0 };
   881→        let adj_r_squared = if n > 1.0 && p > 0.0 {
   882→            1.0 - (rss / df_resid) / (tss / (n - 1.0))
   883→        } else {
   884→            r_squared
   885→        };
   886→
   887→        // F-statistic for overall model significance
   888→        let df_model = if p > 1.0 { p as usize - 1 } else { 0 }; // exclude intercept
   889→        let f_statistic = if df_model > 0 {
   890→            model_f_statistic(rss, tss, df_model, df_resid as usize)
   891→        } else {
   892→            0.0
   893→        };
   894→
   895→        let f_p_value = if df_model > 0 && df_resid > 0.0 {
   896→            f_test_p_value(f_statistic, df_model as i32, df_resid as i32)
   897→        } else {
   898→            1.0
   899→        };
   900→
   901→        // Calculate variance-covariance matrix using weights
   902→        // For GLM: Var(β̂) = dispersion * (X'WX)^(-1)
   903→        let n_vars = self.coefficients.len();
   904→        let x_weighted = Mat::from_fn(self.n_obs, n_vars, |i, j| {
   905→            self.weights[i].sqrt() * self.x_matrix[(i, j)]
   906→        });
   907→
   908→        let xtx = x_weighted.transpose() * &x_weighted;
   909→        let qr = xtx.col_piv_qr();
   910→        let identity = Mat::identity(xtx.nrows(), xtx.ncols());
   911→        let xtx_inv = qr.solve(&identity);
   912→
   913→        // Standard errors for GLM
   914→        let std_errors: Vec<f64> = (0..self.coefficients.len())
   915→            .map(|i| (dispersion * xtx_inv[(i, i)]).sqrt())
   916→            .collect();
   917→
   918→        let t_stats = t_statistics(&self.coefficients, &std_errors);
   919→        let p_values = t_test_p_values(&t_stats, df_resid as i32);
   920→
   921→        let mut coefficient_rows = Vec::new();
   922→        for (i, &coef) in self.coefficients.iter().enumerate() {
   923→            let name = if i == 0 {
   924→                "Intercept".to_string()
   925→            } else {
   926→                format!("X{}", i)
   927→            };
   928→
   929→            coefficient_rows.push(CoefficientRow {
   930→                name,
   931→                estimate: coef,
   932→                std_error: std_errors[i],
   933→                t_value: t_stats[i],
   934→                p_value: p_values[i],
   935→            });
   936→        }
   937→
   938→        ModelSummary {
   939→            coefficients: coefficient_rows,
   940→            r_squared,
   941→            adj_r_squared,
   942→            residual_std_error,
   943→            f_statistic,
   944→            f_p_value,
   945→            df_model,
   946→            df_residual: df_resid as usize,
   947→        }
   948→    }
   949→
   950→    fn bootstrap(&self, n_samples: usize) -> Result<BootstrapResult, ModelError> {
   951→        // Create bootstrap statistic that refits the GLM
   952→        let bootstrap_stat = GlmBootstrapStatistic {
   953→            n_params: self.coefficients.len(),
   954→            family: self.family_name.clone(),
   955→        };
   956→
   957→        let config = BootstrapConfig {
   958→            n_samples,
   959→            seed: Some(42), // For reproducible results
   960→            parallel: true,
   961→        };
   962→
   963→        // Convert faer matrix to ndarray
   964→        let n_cols = self.x_matrix.ncols();
   965→        let mut x_data = Vec::with_capacity(self.n_obs * n_cols);
   966→        for i in 0..self.n_obs {
   967→            for j in 0..n_cols {
   968→                x_data.push(self.x_matrix[(i, j)]);
   969→            }
   970→        }
   971→        let x_view =
   972→            ndarray::ArrayView2::from_shape((self.n_obs, n_cols), &x_data)
   973→                .map_err(|e| ModelError::LinearAlgebra(e.to_string()))?;
   974→
   975→        // Reconstruct y from fitted values and residuals
   976→        let y_data: Vec<f64> = self.fitted_values.iter()
   977→            .zip(self.residuals.iter())
   978→            .map(|(fitted, resid)| fitted + resid)
   979→            .collect();
   980→        let y_view = ndarray::ArrayView1::from(&y_data);
   981→
   982→        bootstrap(x_view, y_view, bootstrap_stat, Some(config))
   983→            .map_err(|e| ModelError::LinearAlgebra(e.to_string()))
   984→    }
   985→}
