  1014→        // Calculate R² for goodness of fit
  1015→        let y_mean: f64 = self
  1016→            .fitted_values
  1017→            .iter()
  1018→            .zip(self.residuals.iter())
  1019→            .map(|(fitted, resid)| fitted + resid)
  1020→            .sum::<f64>()
