  1181→/// Convenience macro for fitting generalized linear models with optional regularization
  1182→///
  1183→/// This macro provides an ergonomic API for fitting GLMs with elastic net regularization
  1184→/// (Lasso and Ridge).
  1185→///
  1186→/// # Examples
  1187→///
  1188→/// ```ignore
  1189→/// // Standard GLM (no regularization)
  1190→/// let fit = glm!(y ~ x1 + x2, data = df, family = Poisson);
  1191→///
  1192→/// // Lasso regression (alpha = 1.0)
  1193→/// let fit = glm!(y ~ x1 + x2, data = df, family = Gaussian, alpha = 1.0, lambda = 0.1);
  1194→///
  1195→/// // Ridge regression (alpha = 0.0)
  1196→/// let fit = glm!(y ~ x1 + x2, data = df, family = Gaussian, alpha = 0.0, lambda = 0.5);
  1197→///
  1198→/// // Elastic net (0 < alpha < 1)
  1199→/// let fit = glm!(y ~ x1 + x2, data = df, family = Gaussian, alpha = 0.5, lambda = 0.2);
  1200→/// ```
  1201→#[macro_export]
  1202→macro_rules! glm {
  1203→    // GLM with regularization
  1204→    ($formula:expr, data = $data:expr, family = $family:expr, alpha = $alpha:expr, lambda = $lambda:expr) => {{
  1205→        // Parse formula and build design matrix
  1206→        let model_spec = $formula; // Assume formula is already parsed
  1207→        let x_matrix = $data.design_matrix(&model_spec)?;
  1208→        let y_vector = $data.response(&model_spec)?;
  1209→        
  1210→        // Decide which model to use based on alpha and lambda
  1211→        if $lambda > 0.0 {
  1212→            if $alpha == 1.0 {
  1213→                // Pure Lasso
  1214→                $crate::Lasso::fit(x_matrix.view(), y_vector.view(), $lambda, None)
  1215→            } else if $alpha == 0.0 {
  1216→                // Pure Ridge
  1217→                $crate::Ridge::fit(x_matrix.view(), y_vector.view(), $lambda, None)
  1218→            } else {
  1219→                // Elastic net - use coordinate descent with custom alpha
  1220→                let config = ::optimcore::CoordinateDescentConfig {
  1221→                    lambda: $lambda,
  1222→                    alpha: $alpha,
  1223→                    ..Default::default()
  1224→                };
  1225→                let result = ::optimcore::coordinate_descent(
  1226→                    x_matrix.view(), 
  1227→                    y_vector.view(), 
  1228→                    Some(config)
  1229→                )?;
  1230→                Ok($crate::RegularizedFit::from_coordinate_descent(
  1231→                    result,
  1232→                    x_matrix,
  1233→                    y_vector,
  1234→                    $lambda,
  1235→                    $alpha
  1236→                ))
  1237→            }
  1238→        } else {
  1239→            // No regularization - use standard GLM
  1240→            $crate::Glm::fit_ndarray(
  1241→                x_matrix.view(),
  1242→                y_vector.view(),
  1243→                $family,
  1244→                None,
  1245→                None
  1246→            )
  1247→        }
  1248→    }};
  1249→    
  1250→    // GLM without regularization
  1251→    ($formula:expr, data = $data:expr, family = $family:expr) => {{
  1252→        glm!($formula, data = $data, family = $family, alpha = 1.0, lambda = 0.0)
  1253→    }};
  1254→}
