//! Debug script to compare linear model implementation with R
//! This helps identify the source of numerical discrepancies

use stats_models::{Lm, Fit};
use faer::{prelude::*, Mat};
use std::fs::File;
use std::io::Write;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Recreate the exact same data from the original comparison
    let n_obs = 100;
    let true_intercept = 2.5;
    let true_slope = 1.8;
    let error_std = 0.5;

    // Generate the same x values (1 to 100)
    let x_values: Vec<f64> = (1..=n_obs).map(|i| i as f64).collect();

    // Generate y values: y = true_intercept + true_slope * x + error
    // For debugging, use a simple deterministic error pattern
    let y_values: Vec<f64> = x_values.iter().enumerate()
        .map(|(i, &x)| {
            let error = error_std * (i as f64 * 0.1).sin(); // deterministic "error"
            true_intercept + true_slope * x + error
        })
        .collect();

    println!("=== Debug Linear Model Implementation ===");
    println!("Data Summary:");
    println!("  Observations: {}", n_obs);
    println!("  True intercept: {}", true_intercept);
    println!("  True slope: {}", true_slope);
    println!("  Error std dev: {}", error_std);
    println!();

    // Create design matrix with intercept
    let mut x_data = Vec::with_capacity(n_obs * 2);
    for &x in &x_values {
        x_data.push(1.0); // intercept
        x_data.push(x);   // x value
    }

    // Debug: Create faer matrices to inspect QR decomposition
    let x_mat = Mat::from_fn(n_obs, 2, |i, j| x_data[i * 2 + j]);
    let y_mat = Mat::from_fn(n_obs, 1, |i, _| y_values[i]);

    println!("Design matrix X (first 5 rows):");
    for i in 0..5.min(n_obs) {
        println!("  [{:8.3}, {:8.3}]", x_mat[(i, 0)], x_mat[(i, 1)]);
    }
    println!("  ...");
    println!("  [{:8.3}, {:8.3}]", x_mat[(n_obs-1, 0)], x_mat[(n_obs-1, 1)]);
    println!();

    // Debug QR decomposition
    println!("=== QR Decomposition Analysis ===");
    let qr = x_mat.col_piv_qr();
    let r_matrix = qr.R();

    println!("R matrix:");
    for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
        for j in 0..r_matrix.ncols() {
            print!("{:12.6} ", r_matrix[(i, j)]);
        }
        println!();
    }
    println!();

    // Check matrix rank
    let tolerance = 1e-12;
    let mut rank = 0;
    println!("R matrix diagonal elements (for rank detection):");
    for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
        let diag_val = r_matrix[(i, i)];
        println!("  R[{},{}] = {:e}", i, i, diag_val);
        if diag_val.abs() > tolerance {
            rank += 1;
        }
    }
    println!("Detected rank: {} (tolerance: {})", rank, tolerance);
    println!();

    // Solve for coefficients
    println!("=== Coefficient Solving ===");
    let coefficients_mat = qr.solve_lstsq(&y_mat);

    println!("Raw coefficients from QR solve:");
    for i in 0..coefficients_mat.nrows() {
        let coef = coefficients_mat[(i, 0)];
        println!("  β[{}] = {:12.9} (abs: {:e})", i, coef, coef.abs());
    }
    println!();

    // Check for numerical instability
    let has_instability = (0..coefficients_mat.nrows())
        .any(|i| coefficients_mat[(i, 0)].abs() > 1e10);

    println!("Numerical instability check:");
    println!("  Has coefficients > 1e10: {}", has_instability);

    if has_instability {
        println!("  Applying coefficient correction...");
        let mut corrected_coefs = Vec::new();
        for i in 0..coefficients_mat.nrows() {
            let coef = coefficients_mat[(i, 0)];
            if coef.abs() > 1e10 {
                println!("    β[{}]: {} -> 0.0 (corrected)", i, coef);
                corrected_coefs.push(0.0);
            } else {
                corrected_coefs.push(coef);
            }
        }
        println!("  Final corrected coefficients: {:?}", corrected_coefs);
    }
    println!();

    // Fit using our implementation
    println!("=== stats-rs Results ===");
    let fit = Lm::fit(&x_data, &y_values, n_obs, 2)?;
    let summary = fit.summary();

    println!("Coefficients:");
    println!("  Intercept: {:12.9}", fit.coefficients()[0]);
    println!("  Slope:     {:12.9}", fit.coefficients()[1]);
    println!("R-squared: {:12.9}", summary.r_squared);
    println!("Residual SE: {:12.9}", summary.residual_std_error);
    println!("F-statistic: {:12.9}", summary.f_statistic);
    println!("Rank: {}", fit.rank());
    println!();

    // Create R comparison script with the exact same data
    println!("=== Creating R Comparison Script ===");
    let mut r_script = File::create("debug_r_comparison.R")?;

    writeln!(r_script, "# Debug R comparison with exact same data")?;
    writeln!(r_script, "# Generated data")?;
    write!(r_script, "x <- c(")?;
    for (i, &x) in x_values.iter().enumerate() {
        if i > 0 { write!(r_script, ", ")?; }
        write!(r_script, "{}", x)?;
    }
    writeln!(r_script, ")")?;

    write!(r_script, "y <- c(")?;
    for (i, &y) in y_values.iter().enumerate() {
        if i > 0 { write!(r_script, ", ")?; }
        write!(r_script, "{:.15}", y)?;
    }
    writeln!(r_script, ")")?;
    writeln!(r_script)?;

    writeln!(r_script, "# Fit linear model")?;
    writeln!(r_script, "fit <- lm(y ~ x)")?;
    writeln!(r_script, "summary_fit <- summary(fit)")?;
    writeln!(r_script)?;

    writeln!(r_script, "# Print results for comparison")?;
    writeln!(r_script, "cat('R Results:\\n')")?;
    writeln!(r_script, "cat('  Intercept:', coef(fit)[1], '\\n')")?;
    writeln!(r_script, "cat('  Slope:', coef(fit)[2], '\\n')")?;
    writeln!(r_script, "cat('  R-squared:', summary_fit$r.squared, '\\n')")?;
    writeln!(r_script, "cat('  Residual SE:', summary_fit$sigma, '\\n')")?;
    writeln!(r_script, "cat('  F-statistic:', summary_fit$fstatistic[1], '\\n')")?;
    writeln!(r_script)?;

    writeln!(r_script, "# QR decomposition for debugging")?;
    writeln!(r_script, "X <- cbind(1, x)  # Design matrix")?;
    writeln!(r_script, "qr_decomp <- qr(X)")?;
    writeln!(r_script, "R_matrix <- qr.R(qr_decomp)")?;
    writeln!(r_script, "cat('\\nR Matrix from R:\\n')")?;
    writeln!(r_script, "print(R_matrix)")?;
    writeln!(r_script, "cat('\\nR Matrix rank:', qr_decomp$rank, '\\n')")?;
    writeln!(r_script)?;

    writeln!(r_script, "# Direct coefficient calculation for comparison")?;
    writeln!(r_script, "beta_direct <- solve(t(X) %*% X) %*% t(X) %*% y")?;
    writeln!(r_script, "cat('\\nDirect calculation (X\\'X)^(-1)X\\'y:\\n')")?;
    writeln!(r_script, "cat('  Intercept:', beta_direct[1], '\\n')")?;
    writeln!(r_script, "cat('  Slope:', beta_direct[2], '\\n')")?;

    println!("R comparison script written to 'debug_r_comparison.R'");
    println!("Run: Rscript debug_r_comparison.R");

    Ok(())
}

