//! Reproducing the exact numerical discrepancy between stats-rs and R

use stats_models::{Lm, Fit};

fn main() {
    println!("=== Reproducing R vs stats-rs Discrepancy ===");

    // Use the EXACT same random seed and data generation as R
    // This simulates set.seed(42) in R with n_obs=100
    let n_obs = 100;

    // Generate same data as R: x ~ N(0,1), y = 2.5 + 1.8*x + N(0, 0.5)
    // For reproducibility, we'll use a deterministic pattern that matches R's output values

    // From the R output, we know R gets:
    // Intercept: 2.455817, Slope: 1.813580
    // Let's reverse engineer data that would produce this with R

    // Create simple test data to isolate the issue
    let x_values: Vec<f64> = (0..n_obs).map(|i| (i as f64 - 50.0) / 50.0).collect();
    let y_values: Vec<f64> = x_values.iter()
        .map(|&x| 2.5 + 1.8 * x + 0.1 * x.sin()) // deterministic noise
        .collect();

    // Create design matrix (intercept + x)
    let mut x_data = Vec::with_capacity(n_obs * 2);
    for &x in &x_values {
        x_data.push(1.0); // intercept
        x_data.push(x);   // x value
