//! ANOVA and experimental design tools
//!
//! This crate provides classical experimental design tools, including
//! Type I/II/III ANOVA and analysis of variance tables that integrate
//! seamlessly with the stats_models linear model infrastructure.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use ndarray::{Array1, Array2, ArrayView1, ArrayView2};
use std::collections::HashMap;

/// ANOVA errors
#[derive(thiserror::Error, Debug)]
pub enum AnovaError {
    /// Invalid model specification
    #[error("Invalid model: {0}")]
    InvalidModel(String),
    /// Computation error
    #[error("Computation error: {0}")]
    Computation(String),
}

/// ANOVA table row
#[derive(Debug, Clone)]
pub struct AnovaRow {
    /// Source of variation
    pub source: String,
    /// Degrees of freedom
    pub df: usize,
    /// Sum of squares
    pub sum_sq: f64,
    /// Mean square (sum_sq / df)
    pub mean_sq: f64,
    /// F-statistic
    pub f_value: f64,
    /// p-value for F-test
    pub p_value: f64,
}

/// ANOVA table
#[derive(Debug)]
pub struct AnovaTable {
    /// Table rows (factors + residuals)
    pub rows: Vec<AnovaRow>,
    /// Total sum of squares
    pub total_sum_sq: f64,
    /// Total degrees of freedom
    pub total_df: usize,
    /// R-squared of the model
    pub r_squared: f64,
}

/// ANOVA type for multi-factor designs
#[derive(Debug, Clone, Copy)]
pub enum AnovaType {
    /// Type I (sequential) - tests each term adjusting for previous terms
    TypeI,
    /// Type II (hierarchical) - tests each term adjusting for all others at same or lower level  
    TypeII,
    /// Type III (marginal) - tests each term adjusting for all other terms
    TypeIII,
}

/// Factor specification for ANOVA
#[derive(Debug, Clone)]
pub struct Factor {
    /// Factor name
    pub name: String,
    /// Factor levels (group assignments)
    pub levels: Vec<usize>,
    /// Number of unique levels
    pub n_levels: usize,
}

impl Factor {
    /// Create a new factor from group assignments
    pub fn new(name: String, groups: &[usize]) -> Self {
        let unique_levels: std::collections::BTreeSet<_> = groups.iter().cloned().collect();
        let n_levels = unique_levels.len();

        Self {
            name,
            levels: groups.to_vec(),
            n_levels,
        }
    }

    /// Create a factor from string labels
    pub fn from_labels(name: String, labels: &[String]) -> Self {
        let mut label_to_index = HashMap::new();
        let mut levels = Vec::new();
        let mut next_index = 0;

        for label in labels {
            let index = *label_to_index.entry(label.clone()).or_insert_with(|| {
                let idx = next_index;
                next_index += 1;
                idx
            });
            levels.push(index);
        }

        Self {
            name,
            levels,
            n_levels: next_index,
        }
    }
}

impl AnovaTable {
    /// Display the ANOVA table in a formatted way
    pub fn summary(&self) -> String {
        let mut output = String::new();
        output.push_str("Analysis of Variance Table\n");
        output.push_str("==========================================\n");
        output.push_str(&format!("{:<12} {:>8} {:>12} {:>12} {:>10} {:>10}\n", 
                                 "Source", "Df", "Sum Sq", "Mean Sq", "F value", "Pr(>F)"));
        output.push_str("------------------------------------------\n");

        for row in &self.rows {
            if row.f_value.is_finite() {
                output.push_str(&format!("{:<12} {:>8} {:>12.6} {:>12.6} {:>10.4} {:>10.6}\n",
                                         row.source, row.df, row.sum_sq, row.mean_sq, 
                                         row.f_value, row.p_value));
            } else {
                output.push_str(&format!("{:<12} {:>8} {:>12.6} {:>12.6} {:>10} {:>10}\n",
                                         row.source, row.df, row.sum_sq, row.mean_sq, 
                                         "", ""));
            }
        }

        output.push_str("------------------------------------------\n");
        output.push_str(&format!("Total        {:>8} {:>12.6}\n", self.total_df, self.total_sum_sq));
        output.push_str(&format!("R-squared: {:.6}\n", self.r_squared));

        output
    }
}

