        let n_levels = unique_levels.len();

        Self {
            name,
            levels: groups.to_vec(),
            n_levels,
        }
    }

    /// Create a factor from string labels
    pub fn from_labels(name: String, labels: &[String]) -> Self {
        let mut label_to_index = HashMap::new();
        let mut levels = Vec::new();
        let mut next_index = 0;

        for label in labels {
            let index = *label_to_index.entry(label.clone()).or_insert_with(|| {
                let idx = next_index;
                next_index += 1;
                idx
            });
            levels.push(index);
        }

        Self {
            name,
            levels,
            n_levels: next_index,
        }
    }
}

impl AnovaTable {
    /// Display the ANOVA table in a formatted way
    pub fn summary(&self) -> String {
        let mut output = String::new();
        output.push_str("Analysis of Variance Table\n");
        output.push_str("==========================================\n");
        output.push_str(&format!("{:<12} {:>8} {:>12} {:>12} {:>10} {:>10}\n", 
                                 "Source", "Df", "Sum Sq", "Mean Sq", "F value", "Pr(>F)"));
        output.push_str("------------------------------------------\n");

        for row in &self.rows {
            if row.f_value.is_finite() {
                output.push_str(&format!("{:<12} {:>8} {:>12.6} {:>12.6} {:>10.4} {:>10.6}\n",
                                         row.source, row.df, row.sum_sq, row.mean_sq, 
                                         row.f_value, row.p_value));
            } else {
                output.push_str(&format!("{:<12} {:>8} {:>12.6} {:>12.6} {:>10} {:>10}\n",
                                         row.source, row.df, row.sum_sq, row.mean_sq, 
                                         "", ""));
            }
        }

        output.push_str("------------------------------------------\n");
        output.push_str(&format!("Total        {:>8} {:>12.6}\n", self.total_df, self.total_sum_sq));
        output.push_str(&format!("R-squared: {:.6}\n", self.r_squared));

        output
    }
}

/// One-way ANOVA computation
pub fn one_way_anova(y: ArrayView1<f64>, groups: &[usize]) -> Result<AnovaTable, AnovaError> {
    let n = y.len();
    if n != groups.len() {
        return Err(AnovaError::InvalidModel(
            "Response and group vectors must have same length".to_string()
        ));
    }

    if n == 0 {
        return Err(AnovaError::InvalidModel("Empty data".to_string()));
    }

    // Get unique groups and their counts
    let unique_groups: std::collections::BTreeSet<_> = groups.iter().cloned().collect();
    let k = unique_groups.len(); // number of groups

    if k < 2 {
        return Err(AnovaError::InvalidModel(
            "Need at least 2 groups for ANOVA".to_string()
        ));
    }

    // Calculate group means and overall mean
    let mut group_sums = HashMap::new();
    let mut group_counts = HashMap::new();

    for (&group, &value) in groups.iter().zip(y.iter()) {
        *group_sums.entry(group).or_insert(0.0) += value;
        *group_counts.entry(group).or_insert(0) += 1;
    }

    let mut group_means = HashMap::new();
    for &group in &unique_groups {
        let sum = group_sums[&group];
        let count = group_counts[&group] as f64;
        group_means.insert(group, sum / count);
    }

    let overall_mean = y.mean().unwrap();

    // Calculate sums of squares
    let mut ss_between = 0.0;
    let mut ss_within = 0.0;

    // Between-group sum of squares (treatment effect)
    for &group in &unique_groups {
        let group_mean = group_means[&group];
        let group_count = group_counts[&group] as f64;
        ss_between += group_count * (group_mean - overall_mean).powi(2);
    }

    // Within-group sum of squares (error)
    for (&group, &value) in groups.iter().zip(y.iter()) {
        let group_mean = group_means[&group];
        ss_within += (value - group_mean).powi(2);
    }

    // Total sum of squares
    let ss_total = y.iter().map(|&yi| (yi - overall_mean).powi(2)).sum::<f64>();

    // Degrees of freedom
    let df_between = k - 1;
    let df_within = n - k;
    let df_total = n - 1;

    // Mean squares
    let ms_between = ss_between / df_between as f64;
    let ms_within = ss_within / df_within as f64;

    // F-statistic and p-value
    let f_value = if ms_within > 1e-16 { ms_between / ms_within } else { f64::INFINITY };
    let p_value = if f_value.is_finite() && df_within > 0 {
        // Use F-distribution CDF (simplified approximation for now)
        f_distribution_p_value(f_value, df_between as i32, df_within as i32)
    } else {
        f64::NAN
    };

    // R-squared
    let r_squared = if ss_total > 1e-16 { ss_between / ss_total } else { 0.0 };

    let rows = vec![
        AnovaRow {
            source: "Treatment".to_string(),
            df: df_between,
            sum_sq: ss_between,
            mean_sq: ms_between,
            f_value,
            p_value,
        },
        AnovaRow {
            source: "Residuals".to_string(),
            df: df_within,
            sum_sq: ss_within,
            mean_sq: ms_within,
            f_value: f64::NAN,
            p_value: f64::NAN,
        },
    ];

    Ok(AnovaTable {
        rows,
        total_sum_sq: ss_total,
        total_df: df_total,
        r_squared,
    })
}

/// Two-way ANOVA computation without interaction
pub fn two_way_anova(
    y: ArrayView1<f64>, 
    factor_a: &Factor, 
    factor_b: &Factor
) -> Result<AnovaTable, AnovaError> {
    let n = y.len();
    if n != factor_a.levels.len() || n != factor_b.levels.len() {
        return Err(AnovaError::InvalidModel(
            "All vectors must have same length".to_string()
        ));
    }

    // Calculate overall mean
    let overall_mean = y.mean().unwrap();
    let ss_total = y.iter().map(|&yi| (yi - overall_mean).powi(2)).sum::<f64>();

    // Calculate factor A main effect
    let mut a_sums = HashMap::new();
    let mut a_counts = HashMap::new();

    for (i, &value) in y.iter().enumerate() {
        let level_a = factor_a.levels[i];
        *a_sums.entry(level_a).or_insert(0.0) += value;
        *a_counts.entry(level_a).or_insert(0) += 1;
    }

    let mut ss_a = 0.0;
    for level in 0..factor_a.n_levels {
        if let (Some(&sum), Some(&count)) = (a_sums.get(&level), a_counts.get(&level)) {
            let mean_a = sum / count as f64;
            ss_a += count as f64 * (mean_a - overall_mean).powi(2);
        }
    }

    // Calculate factor B main effect
    let mut b_sums = HashMap::new();
    let mut b_counts = HashMap::new();

    for (i, &value) in y.iter().enumerate() {
        let level_b = factor_b.levels[i];
        *b_sums.entry(level_b).or_insert(0.0) += value;
        *b_counts.entry(level_b).or_insert(0) += 1;
    }

    let mut ss_b = 0.0;
    for level in 0..factor_b.n_levels {
        if let (Some(&sum), Some(&count)) = (b_sums.get(&level), b_counts.get(&level)) {
            let mean_b = sum / count as f64;
            ss_b += count as f64 * (mean_b - overall_mean).powi(2);
        }
    }

    // Calculate residual sum of squares
    // For now, simplified calculation (proper two-way would require cell means)
    let ss_residual = ss_total - ss_a - ss_b;

    // Degrees of freedom
    let df_a = factor_a.n_levels - 1;
    let df_b = factor_b.n_levels - 1;
    let df_residual = n - factor_a.n_levels - factor_b.n_levels + 1;
    let df_total = n - 1;

    // Mean squares
    let ms_a = ss_a / df_a as f64;
    let ms_b = ss_b / df_b as f64;
    let ms_residual = ss_residual / df_residual as f64;

    // F-statistics and p-values
    let f_a = if ms_residual > 1e-16 { ms_a / ms_residual } else { f64::INFINITY };
    let f_b = if ms_residual > 1e-16 { ms_b / ms_residual } else { f64::INFINITY };

    let p_a = f_distribution_p_value(f_a, df_a as i32, df_residual as i32);
    let p_b = f_distribution_p_value(f_b, df_b as i32, df_residual as i32);

    let r_squared = if ss_total > 1e-16 { (ss_a + ss_b) / ss_total } else { 0.0 };

    let rows = vec![
        AnovaRow {
            source: factor_a.name.clone(),
            df: df_a,
            sum_sq: ss_a,
            mean_sq: ms_a,
            f_value: f_a,
            p_value: p_a,
        },
        AnovaRow {
            source: factor_b.name.clone(),
            df: df_b,
            sum_sq: ss_b,
            mean_sq: ms_b,
            f_value: f_b,
            p_value: p_b,
        },
        AnovaRow {
            source: "Residuals".to_string(),
            df: df_residual,
            sum_sq: ss_residual,
            mean_sq: ms_residual,
            f_value: f64::NAN,
            p_value: f64::NAN,
        },
    ];

    Ok(AnovaTable {
        rows,
        total_sum_sq: ss_total,
        total_df: df_total,
        r_squared,
    })
}

/// Simplified F-distribution p-value calculation
/// This is a placeholder - in production would use a proper statistical library
fn f_distribution_p_value(f_stat: f64, df1: i32, df2: i32) -> f64 {
    if !f_stat.is_finite() || f_stat < 0.0 || df1 <= 0 || df2 <= 0 {
        return f64::NAN;
    }

    // Very simplified approximation using normal distribution for large df2
    // In production, would use proper F-distribution CDF
    if df2 > 30 {
        let chi2_stat = f_stat * df1 as f64;
        // Convert to approximate normal (very rough)
        let z = (chi2_stat - df1 as f64) / (2.0 * df1 as f64).sqrt();
        normal_p_value_upper_tail(z)
    } else {
        // For small df2, return placeholder
        if f_stat > 4.0 { 0.001 } else if f_stat > 2.0 { 0.05 } else { 0.2 }
    }
}

/// Simplified normal distribution upper tail p-value
fn normal_p_value_upper_tail(z: f64) -> f64 {
    if z > 6.0 { return 0.0; }
    if z < -6.0 { return 1.0; }

    // Very rough approximation using complementary error function
    let t = 1.0 / (1.0 + 0.2316419 * z.abs());
    let d = 0.3989423 * (-z * z / 2.0).exp();
    let p = d * t * (0.3193815 + t * (-0.3565638 + t * (1.7814779 + t * (-1.8212560 + t * 1.3302744))));

    if z >= 0.0 { p } else { 1.0 - p }
}

