//! ANOVA R Comparison Example
//! 
//! This demonstrates our ANOVA implementation and compares it with R's results

use anova::{one_way_anova, two_way_anova, Factor};
use ndarray::Array1;
use std::fs::File;
use std::io::Write;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("stats-rs ANOVA vs R Comparison");
    println!("===============================");

    // Example 1: One-way ANOVA
    println!("\n=== One-way ANOVA ===");

    // Three groups with clear differences
    // Control group: [10, 12, 11, 13, 9]   (mean ≈ 11)
    // Treatment 1:   [15, 17, 16, 18, 14]  (mean ≈ 16)  
    // Treatment 2:   [20, 22, 21, 23, 19]  (mean ≈ 21)
    let y_oneway = Array1::from(vec![
        10.0, 12.0, 11.0, 13.0, 9.0,      // Group 0
        15.0, 17.0, 16.0, 18.0, 14.0,     // Group 1  
        20.0, 22.0, 21.0, 23.0, 19.0      // Group 2
    ]);
    let groups_oneway = vec![
        0, 0, 0, 0, 0,  // Control
        1, 1, 1, 1, 1,  // Treatment 1
        2, 2, 2, 2, 2   // Treatment 2
    ];

    let anova_result = one_way_anova(y_oneway.view(), &groups_oneway)?;

    println!("stats-rs One-way ANOVA Results:");
    println!("{}", anova_result.summary());

    // Export data for R comparison
    let mut csv_file = File::create("anova_oneway_data.csv")?;
    writeln!(csv_file, "y,group")?;
    for (i, &y_val) in y_oneway.iter().enumerate() {
        writeln!(csv_file, "{},{}", y_val, groups_oneway[i])?;
    }

    // Example 2: Two-way ANOVA  
    println!("\n=== Two-way ANOVA ===");

    // 2x3 factorial design: Factor A (2 levels) × Factor B (3 levels)
    let y_twoway = Array1::from(vec![
        12.0, 14.0, 16.0,  // A0,B0  A0,B1  A0,B2
        18.0, 20.0, 22.0,  // A1,B0  A1,B1  A1,B2  
        13.0, 15.0, 17.0,  // A0,B0  A0,B1  A0,B2 (replication)
        19.0, 21.0, 23.0   // A1,B0  A1,B1  A1,B2 (replication)
    ]);

    let factor_a = Factor::new("FactorA".to_string(), &[0, 0, 0, 1, 1, 1, 0, 0, 0, 1, 1, 1]);
    let factor_b = Factor::new("FactorB".to_string(), &[0, 1, 2, 0, 1, 2, 0, 1, 2, 0, 1, 2]);

    let twoway_result = two_way_anova(y_twoway.view(), &factor_a, &factor_b)?;

    println!("stats-rs Two-way ANOVA Results:");
    println!("{}", twoway_result.summary());

    // Export two-way data
    let mut csv_file2 = File::create("anova_twoway_data.csv")?;
    writeln!(csv_file2, "y,factorA,factorB")?;
    for (i, &y_val) in y_twoway.iter().enumerate() {
        writeln!(csv_file2, "{},{},{}", y_val, factor_a.levels[i], factor_b.levels[i])?;
    }

    // Generate R comparison script
    let r_script = format!(r#"
# ANOVA R Comparison Script
cat("R ANOVA Results for Comparison\n")
cat("==============================\n\n")

# One-way ANOVA
cat("=== One-way ANOVA ===\n")
data1 <- read.csv("anova_oneway_data.csv")
data1$group <- as.factor(data1$group)

anova1_fit <- aov(y ~ group, data=data1)
anova1_summary <- summary(anova1_fit)

cat("R One-way ANOVA:\n")
print(anova1_summary)

# Extract key statistics for comparison
oneway_stats <- anova1_summary[[1]]
cat("\nComparison values:\n")
cat("Treatment SS:", oneway_stats["group", "Sum Sq"], "\n")
cat("Treatment MS:", oneway_stats["group", "Mean Sq"], "\n") 
cat("Treatment F:", oneway_stats["group", "F value"], "\n")
cat("Treatment p-value:", oneway_stats["group", "Pr(>F)"], "\n")
cat("Residual SS:", oneway_stats["Residuals", "Sum Sq"], "\n")
cat("Residual MS:", oneway_stats["Residuals", "Mean Sq"], "\n")

# Two-way ANOVA
cat("\n=== Two-way ANOVA ===\n")
data2 <- read.csv("anova_twoway_data.csv")  
data2$factorA <- as.factor(data2$factorA)
data2$factorB <- as.factor(data2$factorB)

anova2_fit <- aov(y ~ factorA + factorB, data=data2)
anova2_summary <- summary(anova2_fit)

cat("R Two-way ANOVA:\n")
print(anova2_summary)

# Extract key statistics for comparison
twoway_stats <- anova2_summary[[1]]
cat("\nComparison values:\n")
cat("FactorA SS:", twoway_stats["factorA", "Sum Sq"], "\n")
cat("FactorA F:", twoway_stats["factorA", "F value"], "\n")
cat("FactorB SS:", twoway_stats["factorB", "Sum Sq"], "\n") 
cat("FactorB F:", twoway_stats["factorB", "F value"], "\n")
cat("Residual SS:", twoway_stats["Residuals", "Sum Sq"], "\n")

cat("\n=== Numerical Comparison ===\n")
cat("One-way ANOVA:\n")
cat("  Treatment SS: R = ", sprintf("%.6f", oneway_stats["group", "Sum Sq"]), 
    ", stats-rs = {:.6}\n", sep="")
cat("  Treatment F:  R = ", sprintf("%.6f", oneway_stats["group", "F value"]), 
    ", stats-rs = {:.6}\n", sep="")
cat("  Residual SS:  R = ", sprintf("%.6f", oneway_stats["Residuals", "Sum Sq"]), 
    ", stats-rs = {:.6}\n", sep="")

cat("\nTwo-way ANOVA:\n")  
cat("  FactorA SS: R = ", sprintf("%.6f", twoway_stats["factorA", "Sum Sq"]), 
    ", stats-rs = {:.6}\n", sep="")
cat("  FactorB SS: R = ", sprintf("%.6f", twoway_stats["factorB", "Sum Sq"]), 
    ", stats-rs = {:.6}\n", sep="")
"#, 
        anova_result.rows[0].sum_sq,
        anova_result.rows[0].f_value,
        anova_result.rows[1].sum_sq,
        twoway_result.rows[0].sum_sq,
        twoway_result.rows[1].sum_sq
    );

    std::fs::write("anova_r_comparison.R", r_script)?;

    println!("\n=== Files Generated ===");
    println!("anova_oneway_data.csv    - One-way ANOVA data");
    println!("anova_twoway_data.csv    - Two-way ANOVA data");
    println!("anova_r_comparison.R     - R comparison script");
    println!("\nRun: Rscript anova_r_comparison.R");

    Ok(())
}

