   580→impl Lasso {
   581→    /// Fit a Lasso regression model using coordinate descent
   582→    ///
   583→    /// This implementation uses coordinate descent optimization with L1 regularization
   584→    /// to encourage sparse solutions.
   585→    ///
   586→    /// # Arguments
   587→    /// * `x` - Design matrix as ndarray view (n_observations × n_predictors)
   588→    /// * `y` - Response vector as ndarray view (n_observations)
   589→    /// * `lambda` - L1 regularization parameter (higher values = more regularization)
   590→    /// * `config` - Optional coordinate descent configuration
   591→    pub fn fit(
   592→        x: ArrayView2<f64>,
   593→        y: ArrayView1<f64>,
   594→        lambda: f64,
   595→        config: Option<CoordinateDescentConfig>,
   596→    ) -> Result<RegularizedFit, ModelError> {
   597→        let mut config = config.unwrap_or_default();
   598→        config.lambda = lambda;
   599→        config.alpha = 1.0; // Pure Lasso (L1 only)
   600→
   601→        let result = coordinate_descent(x, y, Some(config))
   602→            .map_err(|e| ModelError::LinearAlgebra(e.to_string()))?;
   603→
   604→        let fitted_values: Vec<f64> = result.linear_predictor.to_vec();
   605→        let residuals: Vec<f64> = y
   606→            .iter()
