   648→        config.lambda = lambda;
   649→        config.alpha = 0.0; // Pure Ridge (L2 only)
   650→
   651→        let result = coordinate_descent(x, y, Some(config))
   652→            .map_err(|e| ModelError::LinearAlgebra(e.to_string()))?;
   653→
   654→        let fitted_values: Vec<f64> = result.linear_predictor.to_vec();
   655→        let residuals: Vec<f64> = y
   656→            .iter()
   657→            .zip(fitted_values.iter())
   658→            .map(|(&y_val, &fitted)| y_val - fitted)
   659→            .collect();
   660→
   661→        // Store matrices for bootstrap resampling
   662→        let x_matrix = Mat::from_fn(x.nrows(), x.ncols(), |i, j| x[[i, j]]);
   663→        let y_vector = y.to_vec();
