/// Fit the linear mixed model using REML or ML estimation
///
/// This implementation uses:
/// - PIRLS (Penalized Iteratively Reweighted Least Squares) algorithm
/// - Sparse matrix algorithms for efficient computation with many groups
/// - Henderson's mixed model equations for optimal computation
/// - REML or ML estimation for variance components
pub fn fit(
    &self,
    x_fixed: ArrayView2<f64>,
    y: ArrayView1<f64>,
    groups: &[usize],
) -> Result<LinearMixedModelFit, MixedModelError> {
    let n_obs = y.len();
    let n_fixed = x_fixed.ncols();

    // Validate inputs
    if x_fixed.nrows() != n_obs {
        return Err(MixedModelError::InvalidModel(
            "Fixed effects design matrix rows don't match response length".to_string(),
        ));
    }

    if groups.len() != n_obs {
        return Err(MixedModelError::InvalidModel(
            "Groups vector length doesn't match response length".to_string(),
        ));
    }

    // Build sparse random effects design matrix (Z)
    let z_matrix = self.build_random_effects_matrix(groups)?;
    let n_random = z_matrix.cols();

    // Configure PIRLS algorithm
    let pirls_config = PirlsConfig {
        max_iter_outer: self.config.max_iter,
        tolerance_outer: self.config.param_tolerance,
        use_reml: self.config.use_reml,
        ..Default::default()
    };

    // Fit using PIRLS algorithm
    let pirls_result = pirls(
        x_fixed,
        &z_matrix,
        y,
        None, // Let PIRLS choose initial variance components
        Some(pirls_config),
    )?;

    // Calculate fitted values and residuals
    let fitted_fixed = x_fixed.dot(&pirls_result.beta);
    let fitted_random = self.calculate_fitted_random(&z_matrix, &pirls_result.u);
    let fitted_values = &fitted_fixed + &fitted_random;
    let residuals = y - &fitted_values;

    // Extract variance components
    let residual_variance = pirls_result.variances[1];
    let random_intercept_variance = pirls_result.variances[0];

    // Build random effects covariance structure
    let mut random_covariance = HashMap::new();
    let mut random_effects_pred = HashMap::new();

    // For simple random intercept model, we have one grouping factor
    if let Some(re_spec) = self.spec.random_effects.first() {
        let group_name = &re_spec.grouping_factor;

        // Random intercept covariance (1x1 matrix)
        let mut cov_matrix = Array2::zeros((1, 1));
        cov_matrix[[0, 0]] = random_intercept_variance;
        random_covariance.insert(group_name.clone(), cov_matrix);

        // Extract group-level random effects predictions
        let group_effects = self.extract_group_effects(&pirls_result.u, groups)?;
        random_effects_pred.insert(group_name.clone(), group_effects);
    }

    // Calculate degrees of freedom
    let df_residual = if self.config.use_reml {
        n_obs - n_fixed
    } else {
        n_obs - n_fixed - n_random
    };

    Ok(LinearMixedModelFit {
        fixed_effects: pirls_result.beta,
        random_covariance,
        random_effects_pred,
        residual_variance,
        log_likelihood: pirls_result.log_likelihood,
        is_reml: self.config.use_reml,
        iterations: pirls_result.iterations,
        fitted_values,
        residuals,
        n_obs,
        df_residual,
    })
}

/// Build sparse random effects design matrix for random intercept model
fn build_random_effects_matrix(&self, groups: &[usize]) -> Result<CsMat<f64>, MixedModelError> {
    let n_obs = groups.len();

    // Get unique groups to determine number of random effects
    let unique_groups: std::collections::BTreeSet<_> = groups.iter().cloned().collect();
    let n_groups = unique_groups.len();

    // Create sparse matrix Z: n_obs × n_groups
    // Each row has exactly one 1.0 in the column corresponding to its group
    let mut builder = SparseRandomEffectsBuilder::new(n_obs, n_groups);

    // Map group IDs to column indices
    let group_to_col: HashMap<usize, usize> = unique_groups
        .iter()
        .enumerate()
        .map(|(col_idx, &group_id)| (group_id, col_idx))
        .collect();

    // Fill the matrix: Z[i, group[i]] = 1.0
    for (obs_idx, &group_id) in groups.iter().enumerate() {
        if let Some(&col_idx) = group_to_col.get(&group_id) {
            builder.add_entry(obs_idx, col_idx, 1.0);
        } else {
            return Err(MixedModelError::InvalidModel(
                "Invalid group ID in groups vector".to_string(),
            ));
        }
    }

    Ok(builder.build())
}

/// Calculate fitted random effects contributions
fn calculate_fitted_random(&self, z_matrix: &CsMat<f64>, u: &Array1<f64>) -> Array1<f64> {
    let n_obs = z_matrix.rows();
    let mut fitted_random = Array1::zeros(n_obs);

    // Compute Z * u
    for (obs_idx, row) in z_matrix.outer_iterator().enumerate() {
        for (&group_idx, &_val) in row.iter() {
            fitted_random[obs_idx] += u[group_idx];
        }
    }

    fitted_random
}

/// Extract group-level random effects predictions
fn extract_group_effects(
    &self,
    u: &Array1<f64>,
    groups: &[usize],
) -> Result<Array2<f64>, MixedModelError> {
    // Get unique groups
    let unique_groups: std::collections::BTreeSet<_> = groups.iter().cloned().collect();
    let n_groups = unique_groups.len();

    // For random intercept model, we have 1 random effect per group
    let mut group_effects = Array2::zeros((n_groups, 1));

    for (effect_idx, &_group_id) in unique_groups.iter().enumerate() {
        group_effects[[effect_idx, 0]] = u[effect_idx];
    }

    Ok(group_effects)
}

