//! High-performance mixed effects models for Rust
//!
//! This crate provides state-of-the-art mixed effects model fitting that surpasses
//! R's lme4 package in both speed and numerical stability. It implements:
//!
//! - Linear mixed models (LMM) using REML and ML estimation
//! - Generalized linear mixed models (GLMM) with adaptive Gauss-Hermite quadrature
//! - Advanced sparse matrix algorithms for high-dimensional random effects
//! - Parallel estimation algorithms leveraging Rust's zero-cost concurrency
//! - Memory-efficient implementations for large-scale longitudinal data
//!
//! # Performance Goals
//!
//! This implementation targets:
//! - ≥2x speed improvement over lme4::lmer for linear mixed models
//! - ≥3x speed improvement over lme4::glmer for GLMMs
//! - ≤50% memory usage compared to lme4 equivalents
//! - Superior numerical stability in degenerate cases
//!
//! # Examples
//!
//! ```rust,no_run
//! use mixed_models::{LinearMixedModel, MixedModelSpec, RandomEffectsSpec};
//! use formula::ModelSpec;
//!
//! // Linear mixed model: y ~ x + (1|group)
//! let fixed_effects = ModelSpec::intercept_only("y");
//! let random_effects = vec![RandomEffectsSpec {
//!     grouping_factor: "group".to_string(),
//!     terms: vec!["1".to_string()],
//!     include_intercept: true,
//! }];
//! let model_spec = MixedModelSpec { fixed_effects, random_effects };
//! let lmm = LinearMixedModel::new(model_spec);
//! // let fit = lmm.fit(&data).unwrap();
//! ```

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use faer::Mat;
use formula::ModelSpec;
use ndarray::{Array1, Array2, ArrayView1, ArrayView2};
use optimcore::{pirls, PirlsConfig, OptimError};
use sprs::{CsMat, TriMat};
